}

/* 文本 */
.mes_block {
    position: relative;
    isolation: isolate;
    background: transparent !important; 
    border: none !important;            
    box-shadow: none !important;        
    backdrop-filter: none !important;   
    width: 100% !important;
    margin: 0 !important;
    padding: 0 !important;overflow: visible !important;
}

.mes_block .ch_name,
.mes_block .mes_text {
    width: 100%;
    box-sizing: border-box;
    margin: 0;
}

/* 文字 */
.mes_text {
    line-height: 1.6 !important;
    letter-spacing: 0.5px;
    word-break: break-word;
    padding-bottom: 0em !important;
    padding-top: 0px !important;
    text-align: justify;
    font-weight: 500;
}
.mes[mesid="0"] .mes_text {padding-top: 19px !important;}
/*文字铺满@墨千尾*/
.mes .mes_text {
    width: 100%;
    padding: 0px;
    margin: 0;
}

/* user文字颜色 */
.mes[is_user="true"] .mes_text {
    color: #e6acc6;
}

/* char文字颜色 */
.mes:not([is_user="true"]) .mes_text {
    color: #6d6d6d;
}

/* 气泡布局 */
#chat {
    display: flex;
    flex-direction: column;
    align-items: center;
    padding-left: 0 !important;
}

#chat .mes {
    top: -57px;
    bottom: 0px;
}

#chat .mes:first-child {
    top: -40px !important;
}

/* 名字&时间戳 */
.mes .ch_name {
    position: absolute !important;
    top: -121px !important;
    left: 119.5px !important;   
    width: auto !important;
    text-align: left !important;
    z-index: 10 !important;font-size: 12px !important;color:#637d93;
}

.mes .timestamp {
    position: absolute !important;
    top: 29px !important;
    left: -6px !important;
    width: auto !important;
    text-align: left !important;
    z-index: 10 !important;
    color:#637d93;
}

/* 头像 */
.mes .avatar img {
  width: 113px !important;
  height: 113px !important;
  object-fit: cover !important;
  border-radius: 50% !important;
  box-shadow: none !important;
  position: relative;
  z-index: 2;
}

.mes .mesAvatarWrapper {
  position: absolute;
  top: 17px;
  left: 16px;
  width: auto;
  padding: 0;
}

.mes .mesAvatarWrapper .avatar {
  flex-basis: auto;
  display: flex;
  justify-content: center;
  position: relative;
  width: 113px;
  height: 113px;
}

/* 头像框部分 */
.mes .avatar::before,
.mes .avatar::after {
  content: "";
  position: absolute;
  background-size: contain;
  background-repeat: no-repeat;
  background-position: center;
  pointer-events: none;
}

/*头像框1*/
.mes .avatar::after {
  background-image: url("data:image/png;base64,iVBORw0KGgoAAAANSUhEUgAAAAEAAAABCAQAAAC1HAwCAAAAC0lEQVR42mNkYAAAAAYAAjCB0C8AAAAASUVORK5CYII=");
  width: 135%;
  height: 135%;
  top: -8%;
  left: -3%;
  z-index: 4;
}
/*头像框2*/
.mes .avatar::before {
  background-image: url("data:image/png;base64,iVBORw0KGgoAAAANSUhEUgAAAAEAAAABCAQAAAC1HAwCAAAAC0lEQVR42mNkYAAAAAYAAjCB0C8AAAAASUVORK5CYII=");
  width: 115%;
  height: 115%;
  top: -14%;
  left: -7%;
  z-index: 3;
}
/* 三元素 */

.mes .mesIDDisplay,
.mes .mes_timer,
.mes .tokenCounterDisplay {
    position: absolute !important;
    z-index: 9 !important;
    display: flex !important;
    flex-direction: row !important;
    align-items: center !important; 
    width: 20px !important; 
    min-width: auto !important;
    height: auto !important;
    font-size: 10px !important; 
    color: #637d93 !important; 
    line-height: 1.1 !important;     
    padding: 0 !important;
    margin: 0 !important;
    background: none !important;
    border: none !important;
    opacity: 1;
    white-space: nowrap !important;
    pointer-events: none; 
    writing-mode: vertical-lr !important;
    text-orientation: upright !important;
}

/* 图标 */
.mes .mesIDDisplay::before,
.mes .mes_timer::before,
.mes .tokenCounterDisplay::before {
    content: '❄️';
    display: block; 
    margin-bottom: 2px; 
    font-size: 10px;
    line-height: 1; 
    text-align: center;
}


/* Char 楼层 */
.mes:not([is_user="true"]) .mesIDDisplay { 
    top: 81px !important;    
    right: -164px !important;  
}
/* Char 时间 */
.mes:not([is_user="true"]) .mes_timer ,.mes[is_user="true"] .mesIDDisplay{ 
    top: 78px !important;    
    right: -176px !important;  
}
/* 字数 */
.mes .tokenCounterDisplay { 
    top: 75px !important;    
    right: -189px !important;
}

/* 隐藏部分 */
.mes[is_user="true"] .mes_timer {
    display: none !important;
}

.mes[mesid="0"] .mes_timer,
.mes[mesid="0"] .tokenCounterDisplay {
    display: none !important;
}

/* 按钮 */
.mes .mes_buttons,
.mes .mes_edit_buttons {
    --buttons-vertical-offset: 99px;
    --buttons-horizontal-offset: -149px;
    --user-buttons-horizontal-offset: 100px;
    --user-buttons-vertical-offset: 98px; 
    position: relative; 
    top: var(--buttons-vertical-offset);
    left: var(--buttons-horizontal-offset);
}

.mes[is_user="true"] .mes_buttons,
.mes[is_user="true"] .mes_edit_buttons {
    --buttons-horizontal-offset: var(--user-buttons-horizontal-offset);
    --buttons-vertical-offset: var(--user-buttons-vertical-offset); 
}

.mes_edit > i,
.extraMesButtonsHint > i {
    display: none !important;
}

